// Lambda@Edge function for CloudFront origin response events
exports.handler = async (event) => {
  // Get the HTML response from the origin
  const htmlResponse = event.Records[0].cf.response;

  // Check if the response is HTML
  if (!htmlResponse || !htmlResponse.headers['content-type'] || htmlResponse.headers['content-type'].toLowerCase() !== 'text/html') {
    return htmlResponse;
  }

  // Get the injection points and content from CloudFront custom headers set by viewer request function
  const injectionPoints = event.Records[0].cf.request.headers['injection-points'];
  const content = event.Records[0].cf.request.headers['content'];

  // Parse the HTML response and insert content at specified locations
  const parsedHtmlResponse = parseHTML(htmlResponse.body);
  for (const injectionPoint of injectionPoints) {
    const element = parsedHtmlResponse.querySelector(injectionPoint.selector);
    if (element) {
      element.innerHTML += content;
    }
  }

  // Return the modified HTML response
  return {
    status: '200',
    headers: {
      'content-type': 'text/html'
    },
    body: parsedHtmlResponse.outerHTML
  };
};

// Parse HTML function
function parseHTML(html) {
  const parser = new DOMParser();
  return parser.parseFromString(html, 'text/html');
}